INSERT INTO dawah_questions (category_id, slug, title, short_answer, detailed_answer, evidences, glossary_terms, sources, keywords, status, is_approved) VALUES

((SELECT id FROM dawah_categories WHERE slug='god-existence'), 'why-god-hidden',
'لماذا لا يُظهر الله نفسه لنا مباشرة؟',
'الاختبار الحقيقي للإيمان يقتضي مساحة للاختيار الحر القائم على التفكر والدليل، لا رؤية قسرية تُلغي معنى الإيمان والاختيار.',
'لو ظهر الله للناس ظهورًا حسيًا قاطعًا لا مجال للشك فيه، لانتفى معنى "الإيمان" أصلًا وتحوّل إلى مجرد علم يقيني قسري كرؤية الشمس، ولانتفت معه حكمة الابتلاء والاختيار الحر التي هي جوهر التكليف الإنساني. الله سبحانه ترك في الكون وفي النفس الإنسانية أدلة كافية وواضحة لمن أراد التفكر والبحث بصدق (نظام الكون، الفطرة، الوحي المنقول بدقة)، لكنه لم يفرض رؤية قسرية تُلغي الاختيار. هذا يشبه فارقًا مهمًا بين معلومة تُفرَض عليك رؤيتها، وحقيقة تكتشفها بنفسك عبر البحث والتأمل — الثانية أعمق أثرًا وأصدق التزامًا. مع ذلك، يذكر الإسلام أن المؤمنين سيرون الله يوم القيامة رؤية حقيقية، فالحجاب هنا دنيوي مرتبط بحكمة الابتلاء لا نفيًا مطلقًا للإمكان.',
'[{"type":"quran","ref":"الأنعام: ١٠٣","text":"لَّا تُدْرِكُهُ الْأَبْصَارُ وَهُوَ يُدْرِكُ الْأَبْصَارَ"}]'::jsonb,
'[]'::jsonb, '[]'::jsonb,
ARRAY['رؤية الله','الابتلاء','الإيمان الحر'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='purpose-of-life'), 'islam-vs-other-religions-meaning',
'كيف يختلف تفسير الإسلام لمعنى الحياة عن باقي الأديان؟',
'يشترك الإسلام مع كثير من الأديان في الإقرار بغاية إلهية للحياة، لكنه يتميز بربط مباشر بلا وسيط بين الإنسان وربه، وبتصور شامل يجمع الدنيا والآخرة في منظومة واحدة متكاملة لا منفصلة.',
'تتفق أغلب الأديان السماوية على وجود غاية إلهية للحياة تتجاوز المتعة المادية المجردة، لكن الإسلام يتميز بعدة ملامح: أولًا، لا وساطة كهنوتية بين الإنسان وربه — كل إنسان يتوجه لله مباشرة بلا حاجة لكاهن أو طقس وساطة. ثانيًا، لا فصل حاد بين "الديني" و"الدنيوي": العمل، والأسرة، والتجارة، كلها يمكن أن تكون عبادة إذا اقترنت بنية صالحة وأخلاق، لا مجرد أنشطة دنيوية منفصلة عن الدين. ثالثًا، الحياة الدنيا في التصور الإسلامي مقدمة واختبار للآخرة الأبدية، لا غاية نهائية في ذاتها ولا عدمًا بلا معنى بعد الموت — وهذا يمنح الحياة إطارًا زمنيًا ممتدًا يتجاوز العمر القصير للفرد.',
'[]'::jsonb, '[]'::jsonb, '[]'::jsonb,
ARRAY['معنى الحياة','مقارنة الأديان'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='prophethood'), 'prophet-vs-messenger',
'ما الفرق بين النبي والرسول؟',
'كل رسول نبي، وليس كل نبي رسولًا — الرسول يأتيه وحي بشريعة جديدة يُبلّغها لقومه، بينما النبي قد يُوحى إليه دون تكليف بتبليغ شريعة جديدة، بل يجدد ويقرر شريعة سابقة.',
'يفرّق علماء العقيدة الإسلامية بين مصطلحين متقاربين: النبي هو من أوحى الله إليه بوحي، سواء كُلِّف بتبليغه للناس أم لا، وسواء جاء بشريعة جديدة أم لا. أما الرسول فهو نبي خُصَّ بأمرين إضافيين: تكليف صريح بتبليغ الرسالة لقومه، وغالبًا شريعة جديدة أو تجديد شريعة سابقة بشكل رسمي. على هذا فكل رسول نبي بالضرورة (لأنه يوحى إليه)، لكن ليس كل نبي رسولًا (فقد يكون مبعوثًا لتجديد شريعة قائمة فقط دون تكليف رسمي بتبليغ جديد). محمد ﷺ نبي ورسول في آنٍ واحد، وهو خاتمهم جميعًا.',
'[{"type":"quran","ref":"الحج: ٥٢","text":"وَمَا أَرْسَلْنَا مِن قَبْلِكَ مِن رَّسُولٍ وَلَا نَبِيٍّ"}]'::jsonb,
'[{"term":"النبي","definition":"من أوحى الله إليه، سواء أُمِر بتبليغ الوحي أم لا."},{"term":"الرسول","definition":"نبي أُمِر بتبليغ رسالة، غالبًا مقترنة بشريعة جديدة أو تجديد شريعة سابقة."}]'::jsonb,
'[]'::jsonb,
ARRAY['النبوة','الرسالة','الفرق بين النبي والرسول'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='quran'), 'quran-translation-enough',
'هل تكفيني قراءة ترجمة معاني القرآن؟',
'ترجمة المعاني وسيلة مفيدة جدًا لفهم المضمون العام، لكنها ليست القرآن ذاته (الذي هو نص عربي معجز بلغته)، بل نقل تقريبي لمعناه قد يفوته بعض الدقائق اللغوية والبلاغية.',
'يرى علماء الإسلام أن "ترجمة القرآن" بالمعنى الدقيق مستحيلة، لأن القرآن معجز في نظمه ولغته العربية ذاتها، لا في معناه المجرد فقط. لذلك يُفضَّل مصطلح "ترجمة معاني القرآن" لا "ترجمة القرآن". هذا لا يعني أن الترجمة عديمة الفائدة، بل هي أداة أساسية ومهمة جدًا لفهم المضمون العام والأحكام والقصص لمن لا يجيد العربية، وننصح بها فورًا لمن يريد التعرف على مضمون القرآن. لكن من أراد التعمق لاحقًا، تعلّم قدر من العربية أو الاستعانة بتفسير موثوق يفتح أبعادًا إضافية لا تصلها الترجمة وحدها دائمًا. لا تنتظر إتقان العربية لتبدأ — ابدأ بالترجمة الآن، وتدرّج لاحقًا إن أحببت.',
'[]'::jsonb, '[]'::jsonb, '[]'::jsonb,
ARRAY['ترجمة القرآن','فهم القرآن'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='worship'), 'worship-vs-ritualism',
'ما الفرق بين العبادة الحقيقية والتديّن الشكلي؟',
'العبادة الحقيقية تقترن بحضور القلب وصدق النية وأثر أخلاقي عملي في الحياة، بينما التديّن الشكلي أداء طقسي خالٍ من هذا الأثر والحضور القلبي.',
'يحذّر الإسلام صراحة من أداء العبادات بلا حضور قلبي أو أثر أخلاقي حقيقي، ويصف مثل هذا الأداء بأنه ناقص القيمة حتى لو استوفى الشكل الظاهري. الصلاة على سبيل المثال شُرعت أصلًا لتنهى صاحبها عن الفحشاء والمنكر — فإن أُدّيت بلا حضور قلب ولا أثر عملي في سلوك المصلي، فقد فقدت جزءًا جوهريًا من مقصودها الشرعي وإن ظلت صحيحة من الناحية الفقهية الشكلية. المطلوب من المسلم الجديد بالذات ليس إتقان الشكل الظاهري أولًا، بل السعي لحضور القلب وصدق النية تدريجيًا مع تعلّم الشكل — الاثنان يترسّخان معًا بالتدريج لا الشكل وحده.',
'[{"type":"quran","ref":"العنكبوت: ٤٥","text":"إِنَّ الصَّلَاةَ تَنْهَىٰ عَنِ الْفَحْشَاءِ وَالْمُنكَرِ"}]'::jsonb,
'[]'::jsonb, '[]'::jsonb,
ARRAY['العبادة','حضور القلب','التدين الشكلي'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='ethics'), 'how-islam-defines-right-wrong',
'كيف يحدد الإسلام الصواب من الخطأ أخلاقيًا؟',
'المرجعية الأساسية هي الوحي (القرآن والسنة الصحيحة)، مع إدراك أن كثيرًا من هذه الأحكام يتوافق مع ما يهتدي إليه العقل السليم والفطرة أصلًا، لا يناقضهما.',
'يرى الإسلام أن مصدر الحكم الأخلاقي النهائي هو الوحي الإلهي، لأن الله وحده يعلم ما يصلح للإنسان علمًا كاملًا لا يخطئ، بخلاف العقل البشري المحدود المتأثر بالهوى والبيئة والزمن. لكن هذا لا يعني تناقضًا مع العقل: أغلب الأحكام الأخلاقية الكبرى في الإسلام (تحريم الظلم والكذب والقتل، والأمر بالعدل والصدق والرحمة) يوافقها العقل السليم والفطرة الإنسانية غير المشوَّهة أصلًا، فالوحي يُرسّخ ويُفصّل ما تميل إليه الفطرة السليمة، لا يناقضها. في مسائل أدق يعجز العقل عن حسمها بيقين (كتفاصيل بعض الأحكام العبادية أو الاجتماعية)، يبقى الوحي هو المرجع الحاسم.',
'[]'::jsonb, '[]'::jsonb, '[]'::jsonb,
ARRAY['مصدر الأخلاق','الوحي والعقل'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='women-family'), 'women-work-in-islam',
'ما حكم عمل المرأة في الإسلام؟',
'عمل المرأة مباح أصلًا، وقد عمل نساء في عهد النبي ﷺ بالتجارة وغيرها، بشرط عدم الإخلال بواجبات دينية أو أسرية أساسية، وضمن ضوابط شرعية عامة كالحشمة.',
'لا يوجد في الإسلام تحريم عام لعمل المرأة؛ فقد عملت نساء في عهد النبي ﷺ نفسه، أشهرهن خديجة رضي الله عنها التي كانت تاجرة ناجحة قبل زواجها من النبي ﷺ وبعده. الأصل الفقهي أن عمل المرأة مباح، ويُنظَّم بضوابط عامة كالحشمة في اللباس والتعامل، وعدم الإخلال الجسيم بواجبات أساسية كرعاية الأبناء الصغار إن لم يوجد بديل مناسب، وهذه موازنة تراعي ظروف كل أسرة على حدة لا حكمًا واحدًا يفرض نفسه على الجميع. تفاصيل هذه الضوابط تختلف تقديراتها الفقهية حسب طبيعة العمل والسياق الاجتماعي، ومسألة تستحق استشارة مباشرة لمن يريد تفصيلًا يراعي ظرفه الخاص.',
'[]'::jsonb, '[]'::jsonb, '[]'::jsonb,
ARRAY['عمل المرأة','المرأة في الإسلام'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='evil-suffering'), 'why-does-god-allow-suffering',
'لماذا يسمح الله بوجود الشر والألم في العالم؟',
'الابتلاء والألم جزء من اختبار الحياة الدنيا الذي يُظهر معادن الناس ويُثيبهم عليه، والشر غالبًا نتيجة اختيارات بشرية حرة لا فعلًا مباشرًا من الله، مع بقاء بعده الأعمق أحيانًا غائبًا عن إدراكنا المحدود.',
'من أعمق الأسئلة الفلسفية واللاهوتية على الإطلاق، ويقدّم الإسلام له عدة عناصر إجابة متكاملة: أولًا، جزء كبير من الشر في العالم (الظلم، الحروب، الجريمة) نتيجة مباشرة لسوء اختيار الإنسان الحر لا فعل إلهي مباشر — فالله منح الإنسان إرادة حرة حقيقية، وهذه الحرية تحمل بالضرورة إمكانية إساءة الاستخدام. ثانيًا، الألم والمصائب (كالمرض والكوارث الطبيعية) جزء من اختبار الحياة الدنيا الذي يُظهر الصبر والإيمان، ويُثاب عليه المؤمن ثوابًا عظيمًا يفوق الألم نفسه في الآخرة. ثالثًا، عقل الإنسان المحدود قد لا يدرك دائمًا الحكمة الكاملة وراء بلاء معين، تمامًا كطفل لا يفهم سبب ألم إبرة طبية ينفعه لاحقًا — وهذا لا يعني غياب الحكمة، بل قصور إدراكنا عنها أحيانًا. هذه مسألة عميقة تستحق نقاشًا موسّعًا مع داعية إن استمر الإشكال في نفسك.',
'[{"type":"quran","ref":"البقرة: ١٥٥-١٥٦","text":"وَلَنَبْلُوَنَّكُم بِشَيْءٍ مِّنَ الْخَوْفِ وَالْجُوعِ ... وَبَشِّرِ الصَّابِرِينَ"}]'::jsonb,
'[]'::jsonb, '[]'::jsonb,
ARRAY['مشكلة الشر','الألم','الابتلاء'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='sharia'), 'what-is-sharia',
'ما هي الشريعة، وهل هي جامدة لا تتغير؟',
'الشريعة منظومة الأحكام الإلهية المنظِّمة لحياة المسلم، تشمل ثوابت قطعية محدودة لا تتغير، ومساحة اجتهادية واسعة قابلة للتفاعل مع الزمان والمكان ضمن ضوابطها.',
'الشريعة في الإسلام ليست كتلة واحدة جامدة كما يُتصوَّر أحيانًا، بل تتكون من طبقتين: أولًا أحكام قطعية ثابتة عددها محدود نسبيًا (كأركان العبادة الأساسية وكبائر المحرَّمات)، لا تتغير بتغير الزمان لأنها مرتبطة بمصالح ثابتة للإنسان. ثانيًا مساحة اجتهادية واسعة جدًا يمارس فيها الفقهاء عبر التاريخ استنباط أحكام تفصيلية جديدة تناسب مستجدات كل عصر (كأحكام المعاملات المالية الحديثة أو القضايا التقنية)، وهذا الاجتهاد هو ما يمنح الشريعة مرونة حقيقية للتفاعل مع الواقع المتغير دون المساس بالثوابت. هذا التمييز بين الثابت والمتغير هو سرّ استمرار تطبيق الشريعة عمليًا عبر عصور مختلفة جدًا دون جمود.',
'[]'::jsonb,
'[{"term":"الاجتهاد","definition":"بذل الفقيه المؤهل جهده لاستنباط حكم شرعي لمسألة لا نص قطعي فيها، بالاستناد إلى أصول الشريعة العامة."}]'::jsonb,
'[]'::jsonb,
ARRAY['الشريعة','الثابت والمتغير','الاجتهاد'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='jihad'), 'what-does-jihad-mean',
'ما معنى الجهاد في الإسلام؟',
'الجهاد لغة يعني "بذل الجهد"، ومعناه في الإسلام أوسع بكثير من القتال: يشمل المجاهدة الداخلية لمقاومة الهوى والشهوات، والدعوة بالحجة والكلمة، وبذل الجهد في الخير عمومًا — والجهاد بمعنى القتال نوع خاص محكوم بشروط وضوابط فقهية صارمة.',
'من أكثر المصطلحات الإسلامية التباسًا في الفهم الشائع خارج الإسلام. "الجهاد" لغويًا من "الجهد"، ويعني بذل الطاقة والجهد في سبيل هدف. في الاستخدام الشرعي، أوسع معاني الجهاد وأكثرها مركزية هو "جهاد النفس": مجاهدة الإنسان لهواه وشهواته ونزعاته السيئة سعيًا للاستقامة، وهذا ما وصفه بعض العلماء بـ"الجهاد الأكبر". يشمل الجهاد أيضًا الدعوة إلى الإسلام بالحجة والحوار الهادئ، وبذل الجهد في طلب العلم أو الإصلاح الاجتماعي. أما الجهاد بمعنى القتال المسلح (وهو نوع واحد محدد من أنواع الجهاد لا كل معناه)، فمحكوم في الفقه الإسلامي بشروط صارمة جدًا: لا يُشرَع إلا بإذن ولي أمر شرعي لدولة، وضمن سياق دفاعي أو استجابة لعدوان واضح غالبًا، وله ضوابط أخلاقية صارمة في التعامل حتى مع الأعداء (تحريم قتل غير المقاتلين، وعدم التمثيل بالجثث، وحفظ العهود). اختزال معنى "الجهاد" بالكامل في العنف تصوير ناقص جدًا لمصطلح شرعي واسع المعنى.',
'[{"type":"quran","ref":"العنكبوت: ٦٩","text":"وَالَّذِينَ جَاهَدُوا فِينَا لَنَهْدِيَنَّهُمْ سُبُلَنَا"}]'::jsonb,
'[{"term":"الجهاد الأكبر","definition":"مجاهدة النفس والهوى، وُصف في تراث بعض العلماء بأنه أعظم أنواع الجهاد."}]'::jsonb,
'[]'::jsonb,
ARRAY['الجهاد','معنى الجهاد','جهاد النفس'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='relations-non-muslims'), 'how-islam-treats-non-muslims',
'كيف يأمر الإسلام بمعاملة غير المسلمين؟',
'يأمر الإسلام بالعدل والبرّ وحسن المعاملة مع غير المسلمين الذين لا يقاتلون المسلمين أو يعتدون عليهم، ويحرّم ظلمهم أو الاعتداء عليهم — العداء ليس هو الأصل في العلاقة.',
'يقرر القرآن صراحة مبدأ عامًا في التعامل مع غير المسلمين المسالمين: البرّ والعدل، لا العداء الافتراضي. هذا يشمل حسن الجوار، والوفاء بالعهود والعقود معهم، والصدق في المعاملات التجارية، وزيارتهم وتبادل الهدايا، بل وصلة القرابة معهم إن وُجدت. النصوص التي تتحدث عن قتال أو حذر ترتبط بسياقات محددة من عدوان فعلي أو نقض عهد، لا بكل غير مسلم بإطلاق. تاريخيًا، عاشت أقليات دينية غير مسلمة (مسيحية ويهودية وغيرها) قرونًا طويلة تحت حكم إسلامي بحقوق محفوظة نسبيًا مقارنة بسياقات تاريخية أخرى كثيرة في نفس الحقب، وإن اختلفت درجة التطبيق باختلاف العصور والحكام كأي منظومة بشرية.',
'[{"type":"quran","ref":"الممتحنة: ٨","text":"لَّا يَنْهَاكُمُ اللَّهُ عَنِ الَّذِينَ لَمْ يُقَاتِلُوكُمْ فِي الدِّينِ وَلَمْ يُخْرِجُوكُم مِّن دِيَارِكُمْ أَن تَبَرُّوهُمْ وَتُقْسِطُوا إِلَيْهِمْ ۚ إِنَّ اللَّهَ يُحِبُّ الْمُقْسِطِينَ"}]'::jsonb,
'[]'::jsonb, '[]'::jsonb,
ARRAY['غير المسلمين','التعايش','العدل'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='islamic-history'), 'religious-minorities-history',
'هل اضطهد المسلمون تاريخيًا الأقليات الدينية؟',
'التاريخ الإسلامي شهد تفاوتًا كبيرًا بين حاكم وآخر وعصر وآخر كأي تاريخ بشري، لكن المبدأ الفقهي العام كفل للأقليات الدينية حقوقًا محددة (حرية العبادة، القضاء الخاص بهم في أحوالهم الشخصية) مقابل التزامات معينة — وهذا يختلف جوهريًا عن إبادة أو تهجير جماعي منظَّم.',
'من الإجابات الأمينة الواجبة هنا: أي حكم على "التاريخ الإسلامي" ككتلة واحدة تعميم غير دقيق، إذ امتد أكثر من ألف عام عبر دول وحكام متفاوتين جدًا في العدل والانضباط، تمامًا كأي حضارة بشرية أخرى امتدت قرونًا. المبدأ الفقهي العام الذي حكم تعامل الدولة الإسلامية تاريخيًا مع الأقليات الدينية غير المسلمة (يُعرَف فقهيًا بأهل الذمة) كفل لهم: حرية ممارسة شعائرهم الدينية، واستقلالية قضائهم الخاص في أحوالهم الشخصية، وحماية أرواحهم وأموالهم، مقابل التزامات محددة كضريبة الجزية بدل الخدمة العسكرية التي كانت مطلوبة من المسلمين. وُجدت بلا شك حالات ظلم فردية أو انحراف عن هذا المبدأ في فترات أو مناطق معينة (كأي نظام بشري تُخالَف مبادئه أحيانًا في التطبيق)، لكن استمرار وجود مجتمعات دينية غير مسلمة كبيرة ومتماسكة حتى اليوم في مناطق حُكمت إسلاميًا قرونًا طويلة (كأقباط مصر) دليل تاريخي ملموس على عدم وجود سياسة إبادة أو تهجير جماعي منظَّم بصفتها القاعدة العامة.',
'[]'::jsonb, '[]'::jsonb, '[]'::jsonb,
ARRAY['الأقليات الدينية','أهل الذمة','التاريخ الإسلامي'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='entering-islam'), 'will-i-lose-family-friends',
'هل سأفقد أسرتي وأصدقائي إذا أسلمت؟',
'ليس بالضرورة — كثيرون يحافظون على علاقاتهم الأسرية والاجتماعية بعد الإسلام، وإن واجه بعضهم تحديات حقيقية في البداية. الإسلام نفسه يأمر ببرّ الوالدين وصلة الرحم حتى مع اختلاف الدين.',
'هذا خوف مشروع وواقعي يواجهه كثير ممن يفكرون في الدخول في الإسلام، ومن الأمانة عدم التهوين منه بإجابة سطحية. الواقع متفاوت: بعض العائلات تتقبل القرار بمرور الوقت ولو بصعوبة أولية، وبعضها يواجه توترًا حقيقيًا قد يطول. الإسلام نفسه يأمر صراحة ببرّ الوالدين وصلة الرحم حتى مع اختلاف الدين تمامًا (ما لم يُطلَب منك معصية الله)، فالحفاظ على العلاقة الأسرية مبدأ ديني لا خيار ثانوي. من الحكمة عمليًا: التروّي في توقيت وطريقة الإخبار حسب ظروف أسرتك الخاصة، عدم استعجال قطيعة غير ضرورية، والتواصل مع داعية للحصول على نصيحة عملية تراعي وضعك تحديدًا قبل اتخاذ خطوات لا رجعة فيها. لست وحدك في هذا التحدي — كثيرون مرّوا بنفس التجربة ووجدوا طرقًا للتعايش تدريجيًا.',
'[]'::jsonb, '[]'::jsonb, '[]'::jsonb,
ARRAY['الأسرة بعد الإسلام','مخاوف قبل الدخول في الإسلام'], 'draft', false),

((SELECT id FROM dawah_categories WHERE slug='new-muslim'), 'how-long-to-learn-islam',
'كم من الوقت يستغرق تعلّم الإسلام؟',
'العمر كله — التعلم في الإسلام رحلة مستمرة لا محطة نهائية، وهذا لا يعني أنك "ناقص" الإسلام في البداية؛ الشهادتان تكفيان لتكون مسلمًا كامل الإيمان من أول لحظة.',
'من أكثر المفاهيم الخاطئة شيوعًا أن على المسلم الجديد "إتقان" كل شيء خلال أسابيع قليلة وإلا فإسلامه ناقص. الحقيقة الشرعية: بمجرد نطق الشهادتين بقلب صادق تصبح مسلمًا كامل الإيمان في نظر الله، ولو لم تكن تعرف بعد تفاصيل فقهية كثيرة. حتى من وُلدوا مسلمين يقضون حياتهم كلها يتعلمون ويتعمقون في دينهم دون أن يتوقفوا أبدًا عن ذلك. المسار المصمَّم على هذه المنصة (ثلاثون يومًا) مدخل عملي أولي لا نهاية للتعلم، وبعده مسار حياة كامل من التعمق التدريجي بلا ضغط زمني ولا شعور بالتقصير. المقياس الحقيقي ليس سرعة الحفظ أو التعلم، بل صدق النية والاستمرار.',
'[]'::jsonb, '[]'::jsonb, '[]'::jsonb,
ARRAY['التعلم التدريجي','المسلم الجديد','لا ضغط زمني'], 'draft', false)
ON CONFLICT (slug) DO NOTHING;
